import { ref, computed } from 'vue'
import { defineStore } from 'pinia'
import { modelConfigApi, type ModelConfigResponse } from '@/api/modules'

/**
 * 模型配置 Store
 * 管理用户自定义的 LLM 模型配置
 * 配置持久化存储在后端数据库，每个账号独立
 */

/** 模型覆盖配置（用于发送给后端的实际配置，包含真实 API Key） */
export interface ModelOverrideConfig {
  provider: string
  apiKey: string
  baseUrl: string
  model: string
}

/** 预设提供商 */
export interface ModelPreset {
  id: string
  name: string
  icon?: string // 保留可选，部分自定义场景可能用到
  svgPath?: string // 品牌官方 SVG 路径
  viewBox?: string // 适配不同的 SVG 视口
  defaultBaseUrl: string
  placeholder: string
}

