export const useModelConfigStore = defineStore('modelConfig', () => {
  // 后端返回的配置数据（脱敏后的，用于展示）
  const serverConfig = ref<ModelConfigResponse | null>(null)

  // 本地缓存的完整配置（包含真实 API Key，用于发送请求）
  // 从 localStorage 恢复（因为后端返回的 API Key 是脱敏的）
  const localConfig = ref<ModelOverrideConfig | null>(loadLocalConfig())

  // 加载状态
  const loading = ref(false)

  // 是否已提交保存过（用于判断是否需要在表单中显示真实 key）
  const hasServerConfig = computed(() => serverConfig.value !== null)

  // 是否正在使用自定义模型
  const isCustomModel = computed(() => {
    // serverConfig 已加载时优先用它判断
    if (serverConfig.value) return serverConfig.value.isActive == 1
    // serverConfig 还没加载完时，看 localStorage 中是否有缓存
    return localConfig.value !== null
  })

  // 当前模型显示名称
  const displayName = computed(() => {
    if (!isCustomModel.value) return '默认模型'
    const cfg = serverConfig.value || localConfig.value
    if (!cfg) return '默认模型'
    const provider = 'provider' in cfg ? cfg.provider : ''
    const model = 'model' in cfg ? cfg.model : ''
    const preset = MODEL_PRESETS.find(p => p.id === provider)
    const providerName = preset?.name || provider
    return `${providerName} / ${model}`
  })

  // 当前提供商图标数据
  const displayIconData = computed<Partial<ModelPreset>>(() => {
    if (!isCustomModel.value) return { icon: '🔧' }
    const cfg = serverConfig.value || localConfig.value
    const provider = cfg && 'provider' in cfg ? cfg.provider : ''
    return MODEL_PRESETS.find(p => p.id === provider) || { icon: '⚙️' }
  })

  // 获取用于请求体的 modelOverride 对象
  // 核心逻辑：只要本地有完整配置且处于启用状态，就注入到请求中
  const modelOverridePayload = computed(() => {
    if (!localConfig.value) return undefined
    // 如果 serverConfig 已加载且标记为禁用，则不注入
    if (serverConfig.value && serverConfig.value.isActive == 0) return undefined
    // 校验必要字段
    if (!localConfig.value.baseUrl || !localConfig.value.model) return undefined
    return {
      provider: localConfig.value.provider,
      apiKey: localConfig.value.apiKey,
      baseUrl: localConfig.value.baseUrl,
      model: localConfig.value.model
    }
  })

  /** 从后端加载用户的模型配置 */
  async function fetchConfig() {
    loading.value = true
    try {
      const resp = await modelConfigApi.getConfig()
      serverConfig.value = resp.data || null
      // 如果后端有配置但本地没有（比如换设备了），用后端脱敏数据填充本地
      // 用户需要重新输入完整 API Key
      if (serverConfig.value && !localConfig.value) {
        localConfig.value = {
          provider: serverConfig.value.provider || '',
          apiKey: '', // 脱敏的 key 不可用，需要用户重新输入
          baseUrl: serverConfig.value.baseUrl || '',
          model: serverConfig.value.model || ''
        }
      }
    } catch (e) {
      console.error('加载模型配置失败:', e)
    } finally {
      loading.value = false
    }
  }

  /** 保存配置到后端 */
  async function saveConfig(config: ModelOverrideConfig) {
    loading.value = true
    try {
      const resp = await modelConfigApi.saveConfig({
        provider: config.provider,
        apiKey: config.apiKey,
        baseUrl: config.baseUrl,
        model: config.model,
        isActive: 1
      })
      serverConfig.value = resp.data
      // 同时保存完整配置到本地（包含真实 API Key）
      localConfig.value = { ...config }
      saveLocalConfig(config)
    } catch (e) {
      console.error('保存模型配置失败:', e)
      throw e
    } finally {
      loading.value = false
    }
  }

  /** 删除配置（回退默认模型） */
  async function deleteConfig() {
    loading.value = true
    try {
      await modelConfigApi.deleteConfig()
      serverConfig.value = null
      localConfig.value = null
      clearLocalConfig()
    } catch (e) {
      console.error('删除模型配置失败:', e)
      throw e
    } finally {
      loading.value = false
    }
  }

  // --- localStorage 辅助（只存 API Key 等敏感信息，避免每次都要重新输入） ---

  function loadLocalConfig(): ModelOverrideConfig | null {
    try {
      const raw = localStorage.getItem('llm-model-config')
      if (raw) return JSON.parse(raw)
    } catch { /* ignore */ }
    return null
  }

  function saveLocalConfig(config: ModelOverrideConfig) {
    localStorage.setItem('llm-model-config', JSON.stringify(config))
  }

  function clearLocalConfig() {
    localStorage.removeItem('llm-model-config')
  }

  return {
    serverConfig,
    localConfig,
    loading,
    hasServerConfig,
    isCustomModel,
    displayName,
    displayIconData,
    modelOverridePayload,
    fetchConfig,
    saveConfig,
    deleteConfig
  }
})
